}
.profil-header p {
  color: #767676;
  margin-top: 10px;
  font-family: Poppins, sans-serif;
}

/* IMPORTANT: Réorganiser - bouton en haut */
.formio-component-mesProfils {
  display: flex;
  flex-direction: column;
  padding: 0 16px;
}

.formio-component-mesProfils .list-group {
  order: 2;
}

.formio-component-mesProfils > button.btn-primary {
  order: 1;
}

/* ===== BOUTON AJOUTER - STYLE MAQUETTE ===== */
.formio-component-mesProfils > button.btn-primary {
  background: #0a6d4d !important;
  border: none !important;
  border-radius: 10px !important;
  max-width: 831px;
