  overflow: hidden;
}

.formio-component-mesProfils > button.btn-primary:hover {
  background: #085c40 !important;
}

.formio-component-mesProfils > button.btn-primary i {
  display: none !important;
}

/* Contenu injecté du bouton */
.btn-ajouter-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  height: 100%;
  padding: 0 18px;
  pointer-events: none;
}

.btn-ajouter-left {
  display: flex;
  align-items: center;
  gap: 12px;
  overflow: hidden;
}

.btn-ajouter-plus {
  width: 28px;
  height: 28px;
  min-width: 28px;
  border-radius: 50%;
  background: #ffffff;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #0a6d4d;
  font-size: 20px;
  font-weight: 700;
