  align-items: center;
  padding: 14px 18px;
  border: 1.5px solid #0f766e;
  border-radius: 10px;
  background: #fff;
  transition: all 0.2s;
  gap: 12px;
  font-family: Poppins, sans-serif;
}

.profil-card:hover {
  background: #f0fdf4;
}

.profil-card.selected {
  background: #ecfdf5;
  border-color: #006A4F;
  border-width: 2px;
}

.profil-card-left {
  display: flex;
  align-items: center;
  gap: 10px;
  overflow: hidden;
}

.profil-card-left img {
  width: 32px;
  height: 22px;
  object-fit: cover;
  border-radius: 2px;
  flex-shrink: 0;
}

.profil-card-name {
  font-weight: 600;
  color: #006A4F;
  font-size: 15px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.profil-card-doc {
  color: #4B5563;
  font-size: 14px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.profil-card-exp {
  color: #6B7280;
  font-size: 13px;
  white-space: nowrap;
}

.profil-card-actions {
  display: flex;
  align-items: center;
  justify-content: flex-end;
}

