  height: 26px;
  min-width: 26px;
  border-radius: 50%;
  border: 2px solid #d1d5db;
  transition: all 0.2s;
  flex-shrink: 0;
  cursor: pointer;
  background: #fff;
}

.profil-card-radio:hover {
  border-color: #006A4F;
  background: #f0fdf4;
}

.profil-card.selected .profil-card-radio {
  border-color: #006A4F;
  border-width: 6px;
  background: #fff;
}

