  }

  .btn-ajouter-text {
    font-size: 14px;
  }

  .btn-ajouter-plus {
    width: 26px;
    height: 26px;
    min-width: 26px;
    font-size: 18px;
  }

  .btn-ajouter-rond {
    width: 24px;
    height: 24px;
    min-width: 24px;
  }

  /* Card - 2 colonnes */
  .profil-card {
