  .profil-card-left {
    grid-column: 1;
    grid-row: 1;
  }

  .profil-card-doc {
    grid-column: 1;
    grid-row: 2;
    font-size: 13px;
  }

  .profil-card-exp {
    display: none;
  }

  .profil-card-actions {
    grid-column: 2;
    grid-row: 1 / 3;
    align-self: center;
  }
}

/* ===== RESPONSIVE - MOBILE (480px) ===== */
