                            "name": "Setup visa check",
                            "type": "customAction",
                            "customAction": "if (window.__visaCheckBound) return;
window.__visaCheckBound = true;

var form = Object.values(Formio.forms)[0];
if (!form) return;

// Trouver l'index du panel info voyageur
var triggerPanelKey = 'information_du_voyage';
var triggerIndex = -1;
form.pages.forEach(function(p, i) {
  if (p.component && p.component.key === triggerPanelKey) triggerIndex = i;
});

if (triggerIndex === -1) return;

var _originalNext = form.nextPage.bind(form);

form.nextPage = function() {
  if (form.page !== triggerIndex) return _originalNext();

  var d = form.submission.data;

  var API_URL = 'https://newapi-voyage.sandbox.gouv.tg/api/v1/proxy/dgdn/checkprice'
    + '?visa_type=' + d.type_visa
    + '&country=' + d.paysEmetteur
    + '&duration=' + d.dureeDuSejour
    + '&entry_type=' + d.typeEntree
    + '&arrived_date=' + d.date_debut_sejour_backend
    + '&travel_document_type=' + d.typeDocument;


  // Loader
  var loader = document.createElement('div');
  loader.id = 'vc-loader';
  loader.style.cssText = 'position:fixed;inset:0;background:rgba(255,255,255,.85);z-index:10001;display:flex;align-items:center;justify-content:center';
  loader.innerHTML = '<div style="text-align:center"><div style="width:40px;height:40px;border:4px solid #e5e7eb;border-top-color:#006A4F;border-radius:50%;animation:spin .8s linear infinite;margin:0 auto 12px"></div><p style="font-family:Poppins,sans-serif;color:#374151">Vérification...</p></div>';
  if (!document.getElementById('vc-spin')) {
    var s = document.createElement('style'); s.id = 'vc-spin';
    s.textContent = '@keyframes spin{to{transform:rotate(360deg)}}';
    document.head.appendChild(s);
  }
  document.body.appendChild(loader);

  fetch(API_URL, {
    method: 'GET',
    headers: { 'Content-Type': 'application/json' },
  })
  .then(function(r) { return r.json(); })
  .then(function(json) {
    var res = json.data || json;
    var el = document.getElementById('vc-loader');
    if (el) el.remove();

    if ( res.message ===	"BESOIN_DE_VISA") {
      data.besoinVisa = 'oui';
      data.coutVisa  = res.price;
      data.typeVisaResult = res.visa_type;
      var setBesoin = form.getComponent('besoinVisa');
      if (setBesoin) setBesoin.setValue('oui');
      var setCout = form.getComponent('coutVisa');
      if (setCout) setCout.setValue(res.price || '');
      var setType = form.getComponent('typeVisaResult');
      if (setType) setType.setValue(res.visa_type || '');
      var setDelai = form.getComponent('delaiVisa');
      if (setDelai) setDelai.setValue(res.delai || '');
    } else {
      data.besoinVisa = 'non';
      data.coutVisa  = null;

      var setBesoin2 = form.getComponent('besoinVisa');
      if (setBesoin2) setBesoin2.setValue('non');
    }
    form.triggerChange();
    setTimeout(function() { _originalNext(); }, 100);
  })
  .catch(function(err) {
    console.error('Visa check error:', err);
    var el = document.getElementById('vc-loader');
    if (el) el.remove();
    alert('Erreur de vérification. Veuillez réessayer.');
  });

  return Promise.resolve();
};",
