                            "customAction": "if (window.__visaDocsBound) return;
window.__visaDocsBound = true;

var form = Object.values(Formio.forms)[0];
if (!form) return;

function loadVisaDocs(){

  var visaCode = form.submission.data.typeVisaResult;
  if (!visaCode) return;

  var cacheKey = '_visaDocsCache_' + visaCode;

  if (window[cacheKey]) {
    form.submission.data.DocumentsVisa = window[cacheKey];

    var c = form.getComponent('DocumentsVisa');
    if (c) c.setValue(window[cacheKey]);

    form.triggerChange();
    return;
  }

  fetch('https://api-citizen-voyage.sandbox.gouv.tg/api/v1/dynamics/visa-types')
  .then(function(res){
    if(!res.ok) throw new Error(res.status);
    return res.json();
  })
  .then(function(json){

    var members = json && json.data && json.data['hydra:member'];
    if (!Array.isArray(members)) return;

    var visa = null;

    for (var i = 0; i < members.length; i++) {
      if (members[i].code === visaCode) {
        visa = members[i];
        break;
      }
    }

    if (!visa) return;

    var settings = visa.upload_file_settings || [];
    var docs = [];

    for (var j = 0; j < settings.length; j++) {
      var s = settings[j];

      if (s.enabled && s.upload_file) {
        docs.push(s.upload_file); // ✅ on garde tout l'objet
      }
    }

    window[cacheKey] = docs;

    form.submission.data.DocumentsVisa = docs;

    var comp = form.getComponent('DocumentsVisa');
    if (comp) comp.setValue(docs);

    form.triggerChange();

  })
  .catch(function(err){
    console.error('Visa documents error:', err);
  });
}

form.on('change', function(e){
  if (e.changed && e.changed.component && e.changed.component.key === 'typeVisaResult') {
    loadVisaDocs();
  }
});

loadVisaDocs();",
