// ─── Helpers ────────────────────────────────────────────────────────

function buildDocCard(setting, isRequired) {
  var uf   = setting.upload_file;
  var desc = getDescriptionEN(uf.description);
  var icon = getIcon(uf.code);
  var borderColor = isRequired ? '#dc2626' : '#d1d5db';
  var bg          = isRequired ? '#fff'    : '#f9fafb';

  return `
    <div style="display:flex;align-items:flex-start;gap:14px;
                padding:14px 16px;
                background:${bg};
                border:1px solid #e5e7eb;
                border-left:4px solid ${borderColor};
                border-radius:8px">
      <span style="font-size:22px;line-height:1">${icon}</span>
      <div style="flex:1">
        <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap">
          <span style="font-weight:600;color:#111827;font-size:14px">${uf.name}</span>
          ${!isRequired
            ? '<span style="font-size:11px;color:#9ca3af;border:1px solid #e5e7eb;padding:1px 7px;border-radius:999px">optionnel</span>'
            : ''}
        </div>
        ${desc
          ? `<p style="color:#6b7280;font-size:12px;margin:4px 0 0;line-height:1.5">${desc}</p>`
          : ''}
      </div>
    </div>`;
}

function getDescriptionEN(raw) {
  if (!raw) return '';
  // Chercher la ligne qui commence par (EN)
  var lines = raw.split(/\r?\n/);
  var enLine = lines.find(function(l) { return l.trim().startsWith('(EN)'); });
  if (enLine) return enLine.replace(/^\(EN\)\s*/, '').trim();
  // Fallback : retourner la 1re ligne non vide
  var first = lines.find(function(l) { return l.trim().length > 0; });
  return first ? first.replace(/^\(FR\)\s*/,'').trim() : '';
}

function getIcon(code) {
  var map = {
    passport_file:               '🛂',
    photo:                       '📷',
    reservation_certificate_file:'✈️',
    travel_assurance_file:       '🛡️',
    hosting_certificate_file:    '🏨',
    account_statement_file:      '🏦',
    invitation_letter_file:      '✉️',
    registration_certificate_file:'🎓',
    idResidentPermit:            '🪪',
    parentage_proof_file:        '👨‍👩‍👧',
    profession_proof_file:       '💼',
    idscan:                      '🪪',
    authorization_file:          '📜',
  };
  return map[code] || '📄';
