        <div class="value">{% if (data.paysEmetteur && data.paysEmetteur.name && data.paysEmetteur.name.common) { %}{{ data.paysEmetteur.flag }} {{ data.paysEmetteur.name.common }}{% } else { %}-{% } %}</div>
