  <script>
    document.querySelectorAll('.modifier-btn').forEach(function(btn) {
      btn.addEventListener('click', function(e) {
        e.preventDefault();
        var page = parseInt(this.getAttribute('data-page'));
        try {
          var forms = Object.values(Formio.forms);
          if (forms && forms.length > 0 && forms[0].setPage) {
            forms[0].setPage(page);
          }
        } catch(err) {
          console.log('Erreur navigation:', err);
        }
      });
    });
  </script>

  <script>
    // Show/hide 3rd consentement checkbox based on visa need
    (function() {
      function checkVisaConsent() {
        var consentVisa = document.getElementById('consent-visa-item');
        if (!consentVisa) return;

        var paysEmetteur = (typeof Formio !== 'undefined') ? 
          Object.values(Formio.forms)[0]?.data?.paysEmetteur : null;
        var paysResidence = (typeof Formio !== 'undefined') ? 
          Object.values(Formio.forms)[0]?.data?.paysResidenc : null;

        var cca2 = (paysEmetteur && typeof paysEmetteur === 'object') ? paysEmetteur.cca2 : paysEmetteur;
        var resCca2 = (paysResidence && typeof paysResidence === 'object') ? paysResidence.cca2 : paysResidence;
        var isTogo = cca2 === 'TG';
        var paysExemptes = ['BJ','BF','CV','CI','GM','GH','GN','GW','LR','ML','MR','NE','NG','SN','SL','TD'];
        var isExempte = paysExemptes.indexOf(cca2) !== -1;

        // Needs visa: pays émetteur ≠ Togo AND non exempté AND résidence ≠ Togo
        var needsVisa = !isTogo && !isExempte && resCca2 !== 'TG';

        consentVisa.style.display = needsVisa ? 'block' : 'none';
        var cb = document.getElementById('consent3');
        if (cb) cb.required = needsVisa;
      }

      setTimeout(checkVisaConsent, 500);
      setTimeout(checkVisaConsent, 1500);
    })();
  </script>

